import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getAgentCrossChainState(agentAddress) {
  const activity = await client.AllChainsService.getAddressActivity(agentAddress);
  const activeChains = activity.data?.items?.map(c => c.name) ?? [];
  const balances = await Promise.all(
    activeChains.map(chain =>
      client.BalanceService.getTokenBalancesForWalletAddress(chain, agentAddress)
    )
  );
  return activeChains.map((chain, i) => ({ chain, items: balances[i].data?.items }));
}
